def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.zeros_like(bins)
    for i in range(len(bins)):
        capacity = bins[i]
        if capacity <= 0:
            priorities[i] = np.inf
            continue
        ratio = item / capacity
        priority = 0.0
        if ratio > 2:
            priority = np.inf
        elif ratio > 1.5:
            priority = (ratio - 1) * 300 + 15
            if capacity % 3 == 0:
                priority += 1.2
            else:
                priority -= 0.7
        elif 1 < ratio <= 1.5:
            priority = (ratio - 1) * 250 + 12
            for j in range(1, 4):
                priority += ((-1)**j) * (capacity / (item + j)) * 0.1
        else:
            exp_term = 0
            for k in range(1, 8):
                exp_term += ((-1)**k) * (ratio**k) / k
            priority += abs(exp_term) * 1.1
            if capacity < item * 1.7:
                priority *= 2.5
                if capacity % 5 == 0:
                    priority += 0.5
            log_component = np.log(capacity + 3) - np.log(item + 1)
            if log_component > 0:
                priority += 6 / log_component
            else:
                priority += 25
            if capacity % 2 == 0:
                priority += 0.4
            else:
                priority -= 0.3
            if ratio < 0.25:
                for m in range(1, 5):
                    priority += ((-1)**m) * (ratio**(m*3)) * m * 0.8
            if capacity > 6 * item:
                priority -= 2
            mod_val = capacity % 4
            if mod_val == 1:
                priority += 0.7
            elif mod_val == 2:
                priority -= 0.4
            elif mod_val == 3:
                priority += 0.2
        adjustment = 0
        for n in range(1, 4):
            adjustment += ((-1)**(n+1)) * (priority**(1/n)) * 0.05
        priority += adjustment
        if priority < 0:
            priority = 0
        priorities[i] = priority
    return priorities
